import axios from 'axios';

const API = axios.create({
  baseURL: 'http://localhost:5000/api',
});

export const AdminService = {
  // Artists
  getAllArtists: () => API.get('/artists'),
  getArtistById: (id: string) => API.get(`/artists/${id}`),
  upsertArtist: (data: any) => API.post('/import/artist', data),
  
  // Artworks
  getAllArtworks: () => API.get('/artworks'),
  getArtworkById: (id: string) => API.get(`/artworks/${id}`),
  upsertArtwork: (data: any) => API.post('/import/artwork', data),

  // Books
  getAllBooks: () => API.get('/books'),
  upsertBook: (data: any) => API.post('/import/book', data),

  // Sections
  getAllSections: () => API.get('/sections'),
  upsertSection: (data: any) => API.post('/import/section', data),

  // Series (FIXES ERROR)
  getAllSeries: () => API.get('/series'),
  upsertSeries: (data: any) => API.post('/import/series', data),
  
  // Taxonomy (FIXES ERROR)
  getAllTaxonomy: () => API.get('/taxonomy'),
  upsertTaxonomy: (data: any) => API.post('/import/taxonomy', data),
};
